package com.democorp.dfp.output;

/** Synthetic DFP code for DREAM codebase memory demos. */
import java.util.HashSet; import java.util.Set; public class OutputCollector { private final Set<String> collectedIdempotencyKeys = new HashSet<>(); public OutputArtifact collectForExecution(String executionId, String taskId, String attemptId) { String idempotencyKey = executionId + ":" + taskId + ":" + attemptId; if (collectedIdempotencyKeys.contains(idempotencyKey)) { return existingArtifact(executionId, taskId, idempotencyKey); } collectedIdempotencyKeys.add(idempotencyKey); OutputArtifact artifact = new OutputArtifact(); artifact.executionId = executionId; artifact.taskId = taskId; artifact.storageKey = "dfp-demo/" + executionId + "/" + taskId + "/result.csv"; artifact.idempotencyKey = idempotencyKey; artifact.checksum = "synthetic-checksum"; return artifact; } private OutputArtifact existingArtifact(String executionId, String taskId, String idempotencyKey) { OutputArtifact artifact = new OutputArtifact(); artifact.executionId = executionId; artifact.taskId = taskId; artifact.idempotencyKey = idempotencyKey; artifact.storageKey = "existing-artifact"; return artifact; } }
